or: pointer;\n    font-size: 1.25rem;\n    color: #4a5568;\n}\n\n.quantity {\n    padding: 0 1rem;\n    font-size: 1.125rem;\n    font-weight: 500;\n}\n\n.date-selector {\n    display: flex;\n    justify-content: space-between;\n    border-top: 1px solid #e2e8f0;\n    padding-top: 0.75rem;\n    border-radius: 0.75rem;\n    border: 1px solid #e2e8f0;\n    background-color: #fff;\n    box-shadow: 0 4px 6px rgba(0, 0, 0, 0.1);\n    overflow: hidden;\n    z-index: 0;\n    position: relative;\n    top: -10px;\n    right: -9px;\n    width: auto;\n}\n\n.date-btn {\n    width: 36px;\n    height: 36px;\n    border-radius: 0.375rem;\n    display: flex;\n    align-items: center;\n    justify-content: center;\n    cursor: pointer;\n    font-size: 0.875rem;\n    font-weight: 500;\n    color: #4a5568;\n}\n\n.date-btn.active {\n    background-color: #553c9a;\n    color: white;\n}",".card-body {\n  padding: 1rem;\n  border-radius: 0.75rem;\n  border: 1px solid #e2e8f0;\n  background-color: #fff;\n  box-shadow: 0 4px 6px rgba(0, 0, 0, 0.1);\n  overflow: hidden;\n  z-index: 2;\n  position: relative;\n}\n\n.card-image {\n  width: 100px;\n  height: 150px;\n  object-fit: cover;\n  border-radius: 0.5rem;\n}\n\n.title {\n  font-size: 1.5rem;\n  font-weight: 700;\n  color: #1a202c;\n  line-height: 1.2;\n}\n\n.subtitle {\n  font-size: 1rem;\n  color: #4a5568;\n  line-height: 1.4;\n}\n\n.price {\n  font-size: 1.5rem;\n  font-weight: 700;\n  color: #1a202c;\n}\n\n.per-day {\n  font-size: 1rem;\n  color: #718096;\n}\n\n.quantity-control {\n  display: flex;\n  align-items: center;\n  margin-top: 0.5rem;\n}\n\n.quantity-btn {\n  width: 32px;\n  height: 32px;\n  border-radius: 0.375rem;\n  border: 1px solid #cbd5e0;\n  background-color: #fff;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  cursor: pointer;\n  font-size: 1.25rem;\n  color: #4a5568;\n}\n\n.quantity {\n  padding: 0 1rem;\n  font-size: 1.125rem;\n  font-weight: 500;\n}\n\n.date-selector {\n  display: flex;\n 